  wire [2:0] mult_0;
  assign mult_0 = shift_reg ^ poly_shifted;

  wire [2:0] mult_1;
  assign mult_1 = {mult_0[1:0], 1'b0} ^ poly_shifted;

  wire [2:0] mult_2;
  assign mult_2 = {mult_1[1:0], 1'b0} ^ poly_shifted;

  always @(*) begin
    io_encoded = {mult_2[0], mult_1[0], mult_0[0]};  // Changed to assign in always block
  end

endmodule
```

